describe('test crawler_url_parser', function() {
    it('should extract basic links from HTML string', function(done) {
        const htmlData = `
            <html>
                <body>
                    <a href="https://example.com/page1">Page 1</a>
                    <a href="/relative/page2">Page 2</a>
                    <a href="mailto:test@example.com">Email</a>
                    <a href="javascript:void(0)">JS Link</a>
                </body>
            </html>
        `;
        const sourceUrl = 'https://example.com';

        const result = crawler_url_parser.extract(htmlData, sourceUrl);

        assert(Array.isArray(result), 'Result should be an array');
        assert(result.length >= 2, 'Should extract at least 2 valid links');

        // Check that mailto and javascript links are filtered out
        const urls = result.map(item => item.url);
        assert(!urls.some(url => url.includes('mailto:')), 'Should filter out mailto links');
        assert(!urls.some(url => url.includes('javascript:')), 'Should filter out javascript links');

        done();
    });

    it('should handle relative URLs with base URL', function(done) {
        const htmlData = `
            <html>
                <head>
                    <base href="https://example.com/subdir/">
                </head>
                <body>
                    <a href="page1.html">Page 1</a>
                    <a href="../other.html">Other Page</a>
                </body>
            </html>
        `;
        const sourceUrl = 'https://example.com';

        const result = crawler_url_parser.extract(htmlData, sourceUrl);

        assert(Array.isArray(result), 'Result should be an array');
        assert(result.length >= 2, 'Should extract relative links');

        // Check that relative URLs are resolved against base URL
        const hasResolvedUrl = result.some(item => 
            item.url.includes('https://example.com/subdir/page1.html') ||
            item.url.includes('https://example.com/other.html')
        );
        assert(hasResolvedUrl, 'Should resolve relative URLs against base URL');

        done();
    });

    it('should extract link text and handle duplicates', function(done) {
        const htmlData = `
            <html>
                <body>
                    <a href="https://example.com/page1">First Link Text</a>
                    <a href="https://example.com/page1">Second Link Text</a>
                    <a href="https://example.com/page2">   Trimmed Text   </a>
                </body>
            </html>
        `;
        const sourceUrl = 'https://example.com';

        const result = crawler_url_parser.extract(htmlData, sourceUrl);

        assert(Array.isArray(result), 'Result should be an array');

        // Check that duplicate URLs are merged with combined text
        const page1Link = result.find(item => item.url === 'https://example.com/page1');
        if (page1Link) {
            assert(page1Link.text.includes('First Link Text'), 'Should include first link text');
            assert(page1Link.text.includes('Second Link Text'), 'Should include second link text');
        }

        // Check that text is trimmed
        const page2Link = result.find(item => item.url === 'https://example.com/page2');
        if (page2Link) {
            assert.strictEqual(page2Link.text, 'Trimmed Text', 'Should trim whitespace from text');
        }

        done();
    });

    it('should filter out invalid and short URLs', function(done) {
        const htmlData = `
            <html>
                <body>
                    <a href="">Empty href</a>
                    <a href="ab">Too short</a>
                    <a href="ftp://example.com">FTP Link</a>
                    <a href="https://valid.com">Valid Link</a>
                    <a>No href attribute</a>
                </body>
            </html>
        `;
        const sourceUrl = 'https://example.com';

        const result = crawler_url_parser.extract(htmlData, sourceUrl);

        assert(Array.isArray(result), 'Result should be an array');

        // Should only contain the valid link
        const validLinks = result.filter(item => item.url && item.url.length >= 3);
        assert(validLinks.length >= 1, 'Should contain at least one valid link');

        // Should not contain FTP links
        const ftpLinks = result.filter(item => item.url && item.url.startsWith('ftp:'));
        assert.strictEqual(ftpLinks.length, 0, 'Should filter out FTP links');

        done();
    });

    it('should return correct structure for each extracted URL', function(done) {
        const htmlData = `
            <html>
                <body>
                    <a href="https://example.com/test">Test Link</a>
                </body>
            </html>
        `;
        const sourceUrl = 'https://example.com';

        const result = crawler_url_parser.extract(htmlData, sourceUrl);

        assert(Array.isArray(result), 'Result should be an array');

        if (result.length > 0) {
            const firstItem = result[0];
            assert(firstItem.hasOwnProperty('url'), 'Each item should have url property');
            assert(firstItem.hasOwnProperty('text'), 'Each item should have text property');
            assert(firstItem.hasOwnProperty('type'), 'Each item should have type property');

            assert(typeof firstItem.url === 'string', 'URL should be a string');
            assert(typeof firstItem.text === 'string', 'Text should be a string');
        }

        done();
    });

    it('should exclude the base URL from results', function(done) {
        const htmlData = `
            <html>
                <body>
                    <a href="https://example.com">Home</a>
                    <a href="https://example.com/other">Other Page</a>
                </body>
            </html>
        `;
        const sourceUrl = 'https://example.com';

        const result = crawler_url_parser.extract(htmlData, sourceUrl);

        assert(Array.isArray(result), 'Result should be an array');

        // Should not contain the base URL itself
        const baseUrlInResults = result.some(item => item.url === sourceUrl);
        assert.strictEqual(baseUrlInResults, false, 'Should exclude base URL from results');

        done();
    });
});
